import React, { useState, useEffect, useRef } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { useSocket } from '../contexts/SocketContext';
import axios from 'axios';
import './Navbar.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const Navbar = () => {
  const { user, logout } = useAuth();
  const { socket } = useSocket();
  const navigate = useNavigate();
  const dropdownRef = useRef(null);
  
  const [showNotifications, setShowNotifications] = useState(false);
  const [notifications, setNotifications] = useState([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [lastCleared, setLastCleared] = useState(null);

  // Check if user is customer
  const isCustomer = user?.role === 'customer';

  // Load notifications from localStorage on mount (only for customers)
  useEffect(() => {
    if (!user || !isCustomer) {
      setNotifications([]);
      setUnreadCount(0);
      return;
    }

    // Check when was the last time notifications were cleared
    const cleared = localStorage.getItem(`notifications_cleared_${user._id}`);
    setLastCleared(cleared);
    
    loadNotifications();
    fetchUnreadCounts();
  }, [user, isCustomer]);

  // Update unread count whenever notifications change
  useEffect(() => {
    const unread = notifications.filter(n => !n.read).length;
    setUnreadCount(unread);
  }, [notifications]);

  // Save to localStorage whenever notifications change
  useEffect(() => {
    if (user && isCustomer) {
      localStorage.setItem(`notifications_${user._id}`, JSON.stringify(notifications));
    }
  }, [notifications, user, isCustomer]);

  // Fetch unread counts from server
  const fetchUnreadCounts = async () => {
    if (!user || !isCustomer) return;
    
    try {
      // Check if user has cleared notifications recently
      const cleared = localStorage.getItem(`notifications_cleared_${user._id}`);
      const clearedTime = cleared ? parseInt(cleared) : 0;
      const oneDayAgo = Date.now() - 24 * 60 * 60 * 1000;
      
      // Only fetch if cleared more than a day ago or never cleared
      if (clearedTime < oneDayAgo || !cleared) {
        const ratingRes = await axios.get(`${API_URL}/ratings/machine/unread-replies`).catch(() => ({ data: { count: 0 } }));
        const messageRes = await axios.get(`${API_URL}/messages/unread-replies`).catch(() => ({ data: { count: 0 } }));
        const returnRes = await axios.get(`${API_URL}/returns/unread-updates`).catch(() => ({ data: { count: 0 } }));

        const totalUnread = (ratingRes.data.count || 0) + (messageRes.data.count || 0) + (returnRes.data.count || 0);
        
        if (totalUnread > 0) {
          fetchAllNotifications();
        }
      }
    } catch (error) {
      console.error('Error fetching unread counts:', error);
    }
  };

  // Fetch all notifications from server
  const fetchAllNotifications = async () => {
    if (!user || !isCustomer) return;

    try {
      // Check if user has cleared notifications
      const cleared = localStorage.getItem(`notifications_cleared_${user._id}`);
      if (cleared) {
        const clearedTime = parseInt(cleared);
        const now = Date.now();
        
        // Only fetch notifications created AFTER the clear time
        const after = new Date(clearedTime).toISOString();
        
        const ratingsRes = await axios.get(`${API_URL}/ratings/machine/my-ratings?after=${after}`).catch(() => ({ data: { data: [] } }));
        const messagesRes = await axios.get(`${API_URL}/messages/my-messages?after=${after}`).catch(() => ({ data: { data: [] } }));
        const returnsRes = await axios.get(`${API_URL}/returns/my-returns?after=${after}`).catch(() => ({ data: { data: [] } }));
        
        const ratings = ratingsRes.data.data || [];
        const messages = messagesRes.data.data || [];
        const returns = returnsRes.data.data || [];

        const serverNotifications = [];

        // Add rating replies
        ratings.forEach(rating => {
          if (rating.adminReply && !rating.replySeenByCustomer) {
            serverNotifications.push({
              id: `rating_${rating._id}`,
              type: 'rating_reply',
              title: '⭐ Reply to Your Rating',
              message: rating.adminReply.length > 50 
                ? rating.adminReply.substring(0, 50) + '...' 
                : rating.adminReply,
              icon: '⭐',
              color: '#10b981',
              link: '/customer/ratings',
              time: rating.repliedAt || rating.updatedAt,
              read: false
            });
          }
        });

        // Add message replies
        messages.forEach(message => {
          if (message.adminReply && message.status === 'replied' && !message.isCustomerRead) {
            serverNotifications.push({
              id: `message_${message._id}`,
              type: 'message_reply',
              title: '💬 Reply to Your Message',
              message: message.adminReply.length > 50 
                ? message.adminReply.substring(0, 50) + '...' 
                : message.adminReply,
              icon: '💬',
              color: '#3b82f6',
              link: '/customer/messages',
              time: message.repliedAt || message.updatedAt,
              read: false
            });
          }
        });

        // Add return updates
        returns.forEach(returnReq => {
          if (returnReq.status !== 'PENDING' && !returnReq.seenByCustomer) {
            const statusMessage = returnReq.status === 'APPROVED' ? 'approved' : 'rejected';
            serverNotifications.push({
              id: `return_${returnReq._id}`,
              type: 'return_update',
              title: '↩️ Return Update',
              message: `Your return has been ${statusMessage}`,
              icon: returnReq.status === 'APPROVED' ? '✅' : '❌',
              color: returnReq.status === 'APPROVED' ? '#10b981' : '#ef4444',
              link: '/customer/returns',
              time: returnReq.processedAt || returnReq.updatedAt,
              read: false
            });
          }
        });

        setNotifications(prev => {
          const existingIds = new Set(prev.map(n => n.id));
          const newNotifs = serverNotifications.filter(n => !existingIds.has(n.id));
          return [...newNotifs, ...prev].slice(0, 30);
        });

      } else {
        // No clear record, fetch all notifications
        const ratingsRes = await axios.get(`${API_URL}/ratings/machine/my-ratings`).catch(() => ({ data: { data: [] } }));
        const messagesRes = await axios.get(`${API_URL}/messages/my-messages`).catch(() => ({ data: { data: [] } }));
        const returnsRes = await axios.get(`${API_URL}/returns/my-returns`).catch(() => ({ data: { data: [] } }));
        
        const ratings = ratingsRes.data.data || [];
        const messages = messagesRes.data.data || [];
        const returns = returnsRes.data.data || [];

        const serverNotifications = [];

        // Add rating replies
        ratings.forEach(rating => {
          if (rating.adminReply && !rating.replySeenByCustomer) {
            serverNotifications.push({
              id: `rating_${rating._id}`,
              type: 'rating_reply',
              title: '⭐ Reply to Your Rating',
              message: rating.adminReply.length > 50 
                ? rating.adminReply.substring(0, 50) + '...' 
                : rating.adminReply,
              icon: '⭐',
              color: '#10b981',
              link: '/customer/ratings',
              time: rating.repliedAt || rating.updatedAt,
              read: false
            });
          }
        });

        // Add message replies
        messages.forEach(message => {
          if (message.adminReply && message.status === 'replied' && !message.isCustomerRead) {
            serverNotifications.push({
              id: `message_${message._id}`,
              type: 'message_reply',
              title: '💬 Reply to Your Message',
              message: message.adminReply.length > 50 
                ? message.adminReply.substring(0, 50) + '...' 
                : message.adminReply,
              icon: '💬',
              color: '#3b82f6',
              link: '/customer/messages',
              time: message.repliedAt || message.updatedAt,
              read: false
            });
          }
        });

        // Add return updates
        returns.forEach(returnReq => {
          if (returnReq.status !== 'PENDING' && !returnReq.seenByCustomer) {
            const statusMessage = returnReq.status === 'APPROVED' ? 'approved' : 'rejected';
            serverNotifications.push({
              id: `return_${returnReq._id}`,
              type: 'return_update',
              title: '↩️ Return Update',
              message: `Your return has been ${statusMessage}`,
              icon: returnReq.status === 'APPROVED' ? '✅' : '❌',
              color: returnReq.status === 'APPROVED' ? '#10b981' : '#ef4444',
              link: '/customer/returns',
              time: returnReq.processedAt || returnReq.updatedAt,
              read: false
            });
          }
        });

        setNotifications(prev => {
          const existingIds = new Set(prev.map(n => n.id));
          const newNotifs = serverNotifications.filter(n => !existingIds.has(n.id));
          return [...newNotifs, ...prev].slice(0, 30);
        });
      }

    } catch (error) {
      console.error('Error fetching notifications:', error);
    }
  };

  // Socket listeners for real-time notifications
  useEffect(() => {
    if (!socket || !user || !isCustomer) return;

    console.log('🔌 Setting up notification listeners');

    const handleRatingReply = (data) => {
      console.log('📩 Rating reply received:', data);
      if (data.userId === user._id) {
        addNotification({
          type: 'rating_reply',
          title: '⭐ Reply to Your Rating',
          message: data.message || 'Admin replied to your feedback',
          icon: '⭐',
          color: '#10b981',
          link: '/customer/ratings',
          data: data
        });
      }
    };

    const handleMessageReply = (data) => {
      console.log('📩 Message reply received:', data);
      if (data.userId === user._id) {
        addNotification({
          type: 'message_reply',
          title: '💬 Reply to Your Message',
          message: data.message || 'Admin replied to your message',
          icon: '💬',
          color: '#3b82f6',
          link: '/customer/messages',
          data: data
        });
      }
    };

    const handleReturnUpdate = (data) => {
      console.log('📩 Return update received:', data);
      if (data.userId === user._id) {
        const statusMessage = data.status === 'APPROVED' ? 'approved' : 'rejected';
        addNotification({
          type: 'return_update',
          title: '↩️ Return Update',
          message: `Your return has been ${statusMessage}`,
          icon: data.status === 'APPROVED' ? '✅' : '❌',
          color: data.status === 'APPROVED' ? '#10b981' : '#ef4444',
          link: '/customer/returns',
          data: data
        });
      }
    };

    socket.on('rating_reply_notification', handleRatingReply);
    socket.on('message_reply_notification', handleMessageReply);
    socket.on('return_status_update', handleReturnUpdate);

    return () => {
      socket.off('rating_reply_notification', handleRatingReply);
      socket.off('message_reply_notification', handleMessageReply);
      socket.off('return_status_update', handleReturnUpdate);
    };
  }, [socket, user, isCustomer]);

  const loadNotifications = () => {
    try {
      // Check if user has ever cleared notifications
      const hasCleared = localStorage.getItem(`notifications_cleared_${user._id}`);
      
      // Try to load from localStorage first
      const stored = localStorage.getItem(`notifications_${user._id}`);
      
      if (stored) {
        // If there are stored notifications, use them
        const parsed = JSON.parse(stored);
        setNotifications(parsed);
        console.log('📂 Loaded notifications:', parsed);
      } 
      // Only add default notifications if:
      // 1. No stored notifications exist
      // 2. User has NEVER cleared notifications before
      else if (!hasCleared) {
        const defaultNotifications = [
          {
            id: Date.now() - 3000,
            type: 'welcome',
            title: '👋 Welcome to AgriVend!',
            message: 'Thank you for being a valued customer.',
            icon: '🎉',
            color: '#10b981',
            link: '/customer/dashboard',
            time: new Date(Date.now() - 3000).toISOString(),
            read: false
          },
          {
            id: Date.now() - 2000,
            type: 'tip',
            title: '💡 Pro Tip',
            message: 'You can rate our machine in the Ratings section!',
            icon: '⭐',
            color: '#f59e0b',
            link: '/customer/ratings',
            time: new Date(Date.now() - 2000).toISOString(),
            read: false
          }
        ];
        
        setNotifications(defaultNotifications);
        localStorage.setItem(`notifications_${user._id}`, JSON.stringify(defaultNotifications));
        console.log('📦 Created default notifications');
      }
      // If hasCleared is true and no stored notifications, keep empty
      else {
        setNotifications([]);
        console.log('📭 No notifications - user has cleared before');
      }
    } catch (error) {
      console.error('Error loading notifications:', error);
    }
  };

  const addNotification = (notification) => {
    const newNotification = {
      id: Date.now(),
      time: new Date().toISOString(),
      read: false,
      ...notification
    };

    setNotifications(prev => {
      // Check for duplicates
      const isDuplicate = prev.some(n => 
        n.type === notification.type && 
        n.message === notification.message &&
        Date.now() - new Date(n.time).getTime() < 5000
      );

      if (isDuplicate) return prev;

      const updated = [newNotification, ...prev].slice(0, 30);
      return updated;
    });

    // Show browser notification
    if (Notification.permission === 'granted' && isCustomer) {
      new Notification(notification.title, {
        body: notification.message,
        icon: '/logo192.png'
      });
    }
  };

  const markAsRead = async (notification) => {
    // Mark as read in UI
    setNotifications(prev => 
      prev.map(n => n.id === notification.id ? { ...n, read: true } : n)
    );

    // Mark as seen in backend based on notification type
    try {
      if (notification.type === 'rating_reply' && notification.id.toString().startsWith('rating_')) {
        const ratingId = notification.id.toString().replace('rating_', '');
        await axios.put(`${API_URL}/ratings/machine/${ratingId}/mark-seen`);
      } else if (notification.type === 'message_reply' && notification.id.toString().startsWith('message_')) {
        const messageId = notification.id.toString().replace('message_', '');
        await axios.put(`${API_URL}/messages/${messageId}/mark-seen`);
      } else if (notification.type === 'return_update' && notification.id.toString().startsWith('return_')) {
        const returnId = notification.id.toString().replace('return_', '');
        await axios.put(`${API_URL}/returns/${returnId}/mark-seen`);
      }
    } catch (error) {
      console.error('Error marking notification as seen:', error);
    }
  };

  const markAllAsRead = async () => {
    // Mark all as read in UI
    setNotifications(prev => prev.map(n => ({ ...n, read: true })));
    
    // In a real app, you'd want to call a bulk update endpoint
    // For now, we'll just mark them as read in localStorage
    if (user && isCustomer) {
      const currentNotifs = [...notifications];
      for (const notif of currentNotifs) {
        await markAsRead(notif);
      }
    }
  };

  const clearAll = () => {
    setNotifications([]);
    if (user && isCustomer) {
      // Set current timestamp as last cleared time
      const clearTime = Date.now();
      localStorage.setItem(`notifications_cleared_${user._id}`, clearTime.toString());
      localStorage.removeItem(`notifications_${user._id}`);
      setLastCleared(clearTime.toString());
      console.log('🗑️ All notifications cleared at', new Date(clearTime).toISOString());
    }
    setShowNotifications(false);
  };

  const handleNotificationClick = (notification) => {
    markAsRead(notification);
    setShowNotifications(false);
    if (notification.link) {
      navigate(notification.link);
    }
  };

  const getTimeAgo = (timestamp) => {
    const now = new Date();
    const then = new Date(timestamp);
    const diffMs = now - then;
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 1) return 'Just now';
    if (diffMins < 60) return `${diffMins} min ago`;
    if (diffHours < 24) return `${diffHours} hour ago`;
    if (diffDays < 7) return `${diffDays} day ago`;
    return then.toLocaleDateString();
  };

  // Request notification permission
  useEffect(() => {
    if (isCustomer && Notification.permission === 'default') {
      Notification.requestPermission();
    }
  }, [isCustomer]);

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // If not logged in, don't show navbar
  if (!user) return null;

  return (
    <nav className="navbar">
      <div className="navbar-container">
        <Link to="/" className="navbar-logo">
          <span className="logo-icon">🌾</span>
          <span className="logo-text">AgriVend</span>
        </Link>

        <div className="navbar-actions">
          {/* Notifications Bell - ONLY FOR CUSTOMERS */}
          {isCustomer && (
            <div className="notification-wrapper" ref={dropdownRef}>
              <button 
                className="notification-btn"
                onClick={() => setShowNotifications(!showNotifications)}
              >
                <span className="notification-icon">🔔</span>
                {unreadCount > 0 && (
                  <span className="notification-badge">{unreadCount}</span>
                )}
              </button>

              {/* Notifications Dropdown */}
              {showNotifications && (
                <div className="notifications-dropdown">
                  <div className="notifications-header">
                    <div>
                      <h3>Notifications</h3>
                      {unreadCount > 0 && (
                        <span className="notification-count">{unreadCount} unread</span>
                      )}
                    </div>
                    <div className="header-actions">
                      {unreadCount > 0 && (
                        <button onClick={markAllAsRead} className="mark-all-read">
                          ✓ Mark all read
                        </button>
                      )}
                      <button onClick={clearAll} className="clear-all">
                        ✗ Clear all
                      </button>
                    </div>
                  </div>

                  <div className="notifications-list">
                    {notifications.length === 0 ? (
                      <div className="no-notifications">
                        <span className="empty-icon">🔔</span>
                        <p>No notifications</p>
                      </div>
                    ) : (
                      notifications.map((notification) => (
                        <div
                          key={notification.id}
                          className={`notification-item ${!notification.read ? 'unread' : ''}`}
                          onClick={() => handleNotificationClick(notification)}
                        >
                          <div 
                            className="notification-icon-wrapper"
                            style={{ backgroundColor: notification.color + '20' }}
                          >
                            <span style={{ color: notification.color }}>{notification.icon}</span>
                          </div>
                          <div className="notification-content">
                            <div className="notification-title">{notification.title}</div>
                            <div className="notification-message">{notification.message}</div>
                            <div className="notification-time">
                              {getTimeAgo(notification.time)}
                            </div>
                          </div>
                          {!notification.read && <span className="unread-dot" />}
                        </div>
                      ))
                    )}
                  </div>
                </div>
              )}
            </div>
          )}

          {/* User Menu - Shows for EVERYONE */}
          <div className="user-menu">
            <span className="user-name">
              {user?.firstName} {user?.lastName}
            </span>
            <span className="user-role">
              {user?.role === 'admin' ? 'Admin' : 'Customer'}
            </span>
            <button onClick={logout} className="logout-btn-nav">
              Logout
            </button>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
